// Валидация входа.
const i = $input.first().json;
const message = (i.message || '').toString().trim();
if (!message) throw new Error('commit message is required');
if (message.length > 500) throw new Error('commit message too long');

// files: массив относительных путей или пусто
const files = Array.isArray(i.files) ? i.files : [];
for (const f of files) {
  if (typeof f !== 'string') throw new Error('files must be strings');
  if (f.includes('..') || f.startsWith('/')) throw new Error(`unsafe path: ${f}`);
}

return [{
  json: {
    message,
    files,
    branch: 'ai-staging',
  }
}];
